            originalCost := dispatch.Assigns[tryIdx].Cost

            if tryIdx == dispatch.AssignsLen {
                dispatch.Assigns[tryIdx] = Assign{}
            }

            savedState := dispatch.Assigns[tryIdx]

            added := dispatch.Assigns[tryIdx].AddShip(shipID, ori, des)
            if !added {
                continue
