		bestAssignIdx := -1
		minDeltaCost := math.MaxFloat64
		savedCosts := make([]float64, dispatch.AssignsLen)

		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			assign := &dispatch.Assigns[idx]
			savedCosts[idx] = assign.Cost

			success := assign.AddShip(id, ori, des)
			if success {
				oldRoute := assign.StationsCurrent
				assign.GenRoute()
				newCost := assign.Cost
				costValid := newCost >= 0 && newCost >= assign.AccumulatedCost

				if costValid {
					deltaCost := newCost - savedCosts[idx]
					if deltaCost < minDeltaCost {
						minDeltaCost = deltaCost
						bestAssignIdx = idx
					}
				}

				assign.RemoveShip(id)
				assign.GenRoute()
				if assign.Cost < 0 && savedCosts[idx] >= 0 {
					assign.Cost = savedCosts[idx]
				}
			}
		}

		fallbackNewAssign := false
		insertSucceeded := false

		if bestAssignIdx >= 0 {
			targetAssign := &dispatch.Assigns[bestAssignIdx]
			ok := targetAssign.AddShip(id, ori, des)
			if ok {
				targetAssign.GenRoute()
				if targetAssign.Cost >= 0 {
					insertSucceeded = true
				} else {
					targetAssign.RemoveShip(id)
					targetAssign.GenRoute()
					fallbackNewAssign = true
				}
			} else {
				fallbackNewAssign = true
			}
		} else {
			fallbackNewAssign = true
		}

		if fallbackNewAssign {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				targetAssign := &dispatch.Assigns[newIdx]
				savedOldCost := targetAssign.Cost
				savedOldAcc := targetAssign.AccumulatedCost

				ok := targetAssign.AddShip(id, ori, des)
				if ok {
					targetAssign.GenRoute()
					if targetAssign.Cost >= 0 {
						dispatch.AssignsLen++
						insertSucceeded = true
					} else {
						targetAssign.RemoveShip(id)
						targetAssign.GenRoute()
						targetAssign.Cost = savedOldCost
						targetAssign.AccumulatedCost = savedOldAcc
					}
				}
			}
		}

		if !insertSucceeded {
			panic(fmt.Sprintf("order %d could not be inserted into any assign", id))
		}

		currentOrderIndex++
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
